{
    "level": "A1–B2",
    "intro": "У цьому підрозділі ти опануєш <strong>порядок слів</strong> в англійській: від базового SVO до позиції прислівників, додатків та emphatic structures.",
    "rules": [
        {
            "label": "Basic Order",
            "color": "emerald",
            "text": "<strong>Subject + Verb + Object</strong> — базова модель англійського речення:",
            "example": "She reads books."
        },
        {
            "label": "Inversion",
            "color": "blue",
            "text": "У питаннях і частині emphatic structures дієслово або auxiliary переходить <strong>перед підмет</strong>:",
            "example": "Do you work here?"
        },
        {
            "label": "Position",
            "color": "amber",
            "text": "Позиція adverbs, objects і complements змінює звучання та фокус речення:",
            "example": "She often works at home."
        }
    ]
}
